-- ============================================================================
-- seed-venues.sql — rich, realistic Nimman/Chiang Mai sample venues (generated).
-- Inserts via fn_create_place (portable geo, sets published + freshness + history).
-- Idempotent: skips if already seeded. Requires seed-agents.sql (agent/admin) first.
-- ============================================================================
DO $seed$
DECLARE
  cid uuid; did uuid;
  agent uuid := '00000000-0000-4000-8000-00000000a6e7';
  admin uuid := '00000000-0000-4000-8000-00000000ad11';
BEGIN
  IF EXISTS (SELECT 1 FROM places WHERE name_i18n->>'en' = 'Rakngao Slow Bar & Roastery') THEN RETURN; END IF;
  SELECT id INTO cid FROM cities WHERE code='CNX';
  SELECT id INTO did FROM districts WHERE slug='nimman';
  PERFORM fn_create_place($v${"name_i18n": {"th": "รากเหง้า สโลว์บาร์ แอนด์ โรสเตอร์", "en": "Rakngao Slow Bar & Roastery", "zh": "根源慢咖啡烘焙坊"}, "description_i18n": {"th": "สโลว์บาร์เล็กๆ ในซอยนิมมานฯ 9 ที่คั่วเมล็ดอาราบิก้าดอยช้าง-ดอยปางขอนเองทุกสัปดาห์ บาริสต้าดริปทีละแก้วบนเคาน์เตอร์ไม้สักพร้อมเล่าโน้ตกลิ่นรสให้ฟัง", "en": "A tiny slow bar tucked into Nimman Soi 9 that roasts its own Doi Chang and Doi Pang Khon arabica every week, with baristas hand-brewing single cups on a teak counter while walking you through the tasting notes."}, "category": "eat", "subcategory": "cafe", "lng": 98.9672, "lat": 18.7968, "opening_hours": {"mon": "08:00-17:00", "tue": "08:00-17:00", "wed": "closed", "thu": "08:00-17:00", "fri": "08:00-18:00", "sat": "08:00-18:00", "sun": "08:00-18:00"}, "amenities": ["wifi", "power_outlet", "aircon", "vegan_options"], "price_band": "3", "phone": "053-217844"}$v$::jsonb, cid, did, agent, admin);
  PERFORM fn_create_place($v${"name_i18n": {"th": "เมฆหมอก คาเฟ่ แอนด์ โรสเตอร์", "en": "Mokmok Coffee Roasters", "zh": "云雾咖啡烘焙所"}, "description_i18n": {"th": "คาเฟ่สไตล์มินิมอลปูนเปลือยกลางนิมมานฯ ซอย 17 จุดเด่นคือสวนหลังบ้านร่มรื่นและเมนูซิกเนเจอร์ \"ส้มยูซุคอลด์บรูว์\" ที่สดชื่นเข้ากับอากาศเชียงใหม่", "en": "A minimalist bare-concrete cafe on Nimman Soi 17, known for its leafy back garden and a signature yuzu cold brew that cuts perfectly through the Chiang Mai heat."}, "category": "eat", "subcategory": "cafe", "lng": 98.9701, "lat": 18.7991, "opening_hours": {"mon": "07:30-18:00", "tue": "07:30-18:00", "wed": "07:30-18:00", "thu": "07:30-18:00", "fri": "07:30-19:00", "sat": "07:30-19:00", "sun": "07:30-19:00"}, "amenities": ["wifi", "power_outlet", "aircon", "outdoor_seating", "pet_friendly", "parking"], "price_band": "2", "phone": "053-894612"}$v$::jsonb, cid, did, agent, admin);
  PERFORM fn_create_place($v${"name_i18n": {"th": "บ้านไม้สัก เอสเปรสโซ บาร์", "en": "Baan Maisak Espresso Bar", "zh": "柚木屋意式咖啡吧"}, "description_i18n": {"th": "เอสเปรสโซบาร์ในเรือนไม้สักเก่าซอยนิมมานฯ 11 ที่ดึงรสจากเครื่อง La Marzocco วินเทจ เสิร์ฟแฟลตไวต์เข้มข้นคู่ครัวซองต์อบใหม่ทุกเช้า", "en": "An espresso bar set inside a restored old teakwood house on Nimman Soi 11, pulling shots from a vintage La Marzocco and pairing rich flat whites with croissants baked fresh each morning."}, "category": "eat", "subcategory": "cafe", "lng": 98.9685, "lat": 18.8016, "opening_hours": {"mon": "08:00-16:30", "tue": "08:00-16:30", "wed": "08:00-16:30", "thu": "08:00-16:30", "fri": "08:00-16:30", "sat": "08:00-17:30", "sun": "closed"}, "amenities": ["wifi", "power_outlet", "aircon", "outdoor_seating"], "price_band": "3", "phone": "053-326078"}$v$::jsonb, cid, did, agent, admin);
  PERFORM fn_create_place($v${"name_i18n": {"th": "ข้าวซอยแม่สาย นิมมาน", "en": "Khao Soi Mae Sai Nimman", "zh": "湄赛金面餐厅"}, "description_i18n": {"th": "ร้านข้าวซอยสไตล์เชียงใหม่แท้ในซอยนิมมานเหมินทร์ น้ำแกงเข้มข้นกลมกล่อมด้วยกะทิและเครื่องแกงคั่วเอง เสิร์ฟพร้อมเส้นบะหมี่กรอบโรยหน้า หอมแดงดอง ผักกาดดอง และมะนาว เลือกได้ทั้งไก่ เนื้อ และหมู ราคาเป็นกันเองแบบร้านท้องถิ่น เผ็ดน้อยปรับได้ตามใจ", "en": "An old-school Chiang Mai khao soi house tucked into a Nimman soi. The curry broth is rich and balanced with coconut milk and house-roasted curry paste, topped with crispy fried egg noodles and served with pickled shallots, pickled mustard greens and lime on the side. Choose chicken, beef or pork. Local prices, gentle queue at lunch, spice adjustable on request."}, "category": "eat", "subcategory": "restaurant", "lng": 98.9672, "lat": 18.7958, "opening_hours": {"mon": "08:30-15:30", "tue": "08:30-15:30", "wed": "08:30-15:30", "thu": "08:30-15:30", "fri": "08:30-15:30", "sat": "08:30-15:30", "sun": "closed"}, "amenities": ["dine_in", "takeaway", "cash_only", "halal_options", "fan_seating", "street_parking"], "price_band": "1", "phone": "+66 53 894 522"}$v$::jsonb, cid, did, agent, admin);
  PERFORM fn_create_place($v${"name_i18n": {"th": "ป้าแดง หมูปิ้งนิมมาน ซอย 11", "en": "Pa Daeng Grilled Pork Skewers (Nimman Soi 11)", "zh": "红姨烤猪肉串"}, "description_i18n": {"th": "แผงหมูปิ้งหน้าปากซอยนิมมาน 11 เปิดตั้งแต่เช้าตรู่ หมูหมักสูตรป้าแดงปิ้งบนเตาถ่านจนหอมเกรียม เนื้อนุ่มฉ่ำ กินคู่ข้าวเหนียวร้อนๆ ห่อใบตอง น้ำจิ้มแจ่วรสจัดจ้าน เป็นมื้อเช้าและของกินเล่นยอดฮิตของคนทำงานแถวนิมมาน ของหมดเร็วมาก", "en": "A charcoal grill at the mouth of Nimman Soi 11 that fires up before dawn. Pa Daeng's marinated pork skewers char beautifully over coals, juicy and faintly sweet, paired with steaming sticky rice wrapped in banana leaf and a punchy jaew dipping sauce. A beloved breakfast and snack stop for Nimman office workers, it regularly sells out by mid-morning."}, "category": "eat", "subcategory": "street_food", "lng": 98.9701, "lat": 18.8003, "opening_hours": {"mon": "05:30-11:00", "tue": "05:30-11:00", "wed": "05:30-11:00", "thu": "05:30-11:00", "fri": "05:30-11:00", "sat": "05:30-11:00", "sun": "05:30-11:00"}, "amenities": ["takeaway", "cash_only", "outdoor_seating", "no_seating", "halal_options"], "price_band": "1", "phone": "+66 81 472 6630"}$v$::jsonb, cid, did, agent, admin);
  PERFORM fn_create_place($v${"name_i18n": {"th": "เรือนมะพร้าว ข้าวเหนียวมะม่วง & น้ำแข็งไส", "en": "Coconut House Mango Sticky Rice & Shaved Ice", "zh": "椰子屋芒果糯米饭甜品店"}, "description_i18n": {"th": "ร้านขนมหวานไทยบรรยากาศบ้านไม้ในนิมมาน ซอย 7 เด่นด้วยข้าวเหนียวมะม่วงน้ำดอกไม้ราดกะทิสดข้นมัน โรยถั่วทองคั่ว และน้ำแข็งไสใส่ลอดช่อง ขนุน เฉาก๊วย ราดน้ำกะทิหอมใบเตย หวานเย็นชื่นใจคลายร้อนเชียงใหม่ มีที่นั่งในสวนเล็กๆ ร่มรื่น", "en": "A wooden-house Thai dessert spot on Nimman Soi 7. The signature is fragrant Nam Dok Mai mango with warm sticky rice, thick fresh coconut cream and toasted mung beans, alongside old-style shaved ice (nam kaeng sai) loaded with lod chong, jackfruit and grass jelly under pandan-scented coconut syrup. A cool, leafy little garden seating area makes it a perfect Chiang Mai heat escape."}, "category": "eat", "subcategory": "dessert", "lng": 98.9685, "lat": 18.7981, "opening_hours": {"mon": "11:00-20:00", "tue": "11:00-20:00", "wed": "closed", "thu": "11:00-20:00", "fri": "11:00-20:00", "sat": "10:30-21:00", "sun": "10:30-21:00"}, "amenities": ["dine_in", "takeaway", "outdoor_seating", "garden_seating", "vegetarian_options", "air_conditioning", "card_accepted", "wifi"], "price_band": "2", "phone": "+66 53 216 089"}$v$::jsonb, cid, did, agent, admin);
  PERFORM fn_create_place($v${"name_i18n": {"th": "วัดอุโมงค์ (สวนพุทธธรรม)", "en": "Wat Umong (Suan Phutthatham)", "zh": "伍蒙寺（隧道寺）"}, "description_i18n": {"th": "วัดป่าเก่าแก่อายุกว่า 700 ปี เชิงดอยสุเทพ จุดเด่นคืออุโมงค์ก่ออิฐโบราณที่มีภาพจิตรกรรมเลือนราง เดินลอดเข้าไปกราบพระได้จริง รอบวัดร่มรื่นด้วยต้นไม้ใหญ่ มีเจดีย์ทรงระฆังเก่า บึงน้ำที่มีปลาและนกพิราบ ป้ายปริศนาธรรมแขวนตามต้นไม้ บรรยากาศเงียบสงบเหมาะนั่งสมาธิ ห่างจากนิมมานฯ ราว 10 นาทีโดยรถ", "en": "A serene 700-year-old forest temple at the foot of Doi Suthep, famous for its ancient brick tunnels lined with faded murals that you can actually walk through to reach Buddha images. Towering trees shade a weathered bell-shaped chedi and a fish-and-pigeon pond, with Dharma riddle signs hung along the paths. Wonderfully quiet and meditative, about 10 minutes by car from Nimman."}, "category": "see", "subcategory": "temple", "lng": 98.9602, "lat": 18.7886, "opening_hours": {"mon": "06:00-17:00", "tue": "06:00-17:00", "wed": "06:00-17:00", "thu": "06:00-17:00", "fri": "06:00-17:00", "sat": "06:00-17:00", "sun": "06:00-17:00"}, "amenities": ["parking", "restroom", "photo_spot", "wheelchair_access"], "phone": "+66 53 810 184"}$v$::jsonb, cid, did, agent, admin);
  PERFORM fn_create_place($v${"name_i18n": {"th": "จุดชมวิวดอยสุเทพ (ผาดูดาว)", "en": "Doi Suthep Viewpoint (Pha Dudao)", "zh": "素贴山观景台（看星岩）"}, "description_i18n": {"th": "จุดชมวิวริมถนนขึ้นดอยสุเทพ มองลงมาเห็นเมืองเชียงใหม่ทั้งเมืองในมุมกว้าง สวยทั้งช่วงเช้าที่หมอกลอยเหนือเมืองและช่วงค่ำที่ไฟเมืองส่องระยิบ มีลานจอดรถเล็ก ๆ ร้านกาแฟและของว่างริมทาง นักท่องเที่ยวนิยมแวะถ่ายรูปก่อนขึ้นไปวัดพระธาตุดอยสุเทพ ขับจากนิมมานฯ ขึ้นมาราว 15 นาที", "en": "A roadside lookout on the climb up Doi Suthep, offering a sweeping panorama of the entire Chiang Mai valley. Magical at dawn when mist hangs over the city and again at dusk when the city lights sparkle below. A small parking area and roadside coffee-and-snack stalls make it a favorite photo stop before continuing up to Wat Phra That Doi Suthep, about 15 minutes' drive from Nimman."}, "category": "see", "subcategory": "viewpoint", "lng": 98.9685, "lat": 18.8055, "opening_hours": {"mon": "05:00-20:00", "tue": "05:00-20:00", "wed": "05:00-20:00", "thu": "05:00-20:00", "fri": "05:00-20:00", "sat": "05:00-20:00", "sun": "05:00-20:00"}, "amenities": ["parking", "photo_spot"]}$v$::jsonb, cid, did, agent, admin);
  PERFORM fn_create_place($v${"name_i18n": {"th": "หอศิลปวัฒนธรรมเมืองเชียงใหม่", "en": "Chiang Mai City Arts and Cultural Centre", "zh": "清迈城市艺术文化中心"}, "description_i18n": {"th": "พิพิธภัณฑ์ในอาคารราชการเก่าสไตล์โคโลเนียลกลางเมือง ตรงข้ามอนุสาวรีย์สามกษัตริย์ จัดแสดงเรื่องราวประวัติศาสตร์ล้านนา ตั้งแต่ยุคก่อตั้งเมือง วิถีชีวิต ประเพณี ไปจนถึงหุ่นจำลองและห้องจัดแสดงเสมือนจริง เหมาะกับคนอยากเข้าใจรากเหง้าเชียงใหม่ก่อนเที่ยวที่อื่น มีลานกว้างด้านหน้าให้นั่งพักและถ่ายรูป", "en": "Housed in a graceful colonial-era former provincial hall in the old city, opposite the Three Kings Monument, this museum tells the story of Lanna history from the city's founding through its customs, daily life, dioramas and immersive recreated rooms. A great primer for understanding Chiang Mai's roots before exploring elsewhere, with a spacious plaza out front for resting and photos."}, "category": "see", "subcategory": "museum", "lng": 98.987, "lat": 18.7905, "opening_hours": {"mon": "Closed", "tue": "08:30-17:00", "wed": "08:30-17:00", "thu": "08:30-17:00", "fri": "08:30-17:00", "sat": "08:30-17:00", "sun": "08:30-17:00"}, "amenities": ["parking", "restroom", "guided_tour", "photo_spot", "wheelchair_access"], "price_band": "1", "phone": "+66 53 217 793"}$v$::jsonb, cid, did, agent, admin);
  PERFORM fn_create_place($v${"name_i18n": {"th": "ครัวไทยการ์เด้น สอนทำอาหารเหนือ", "en": "Thai Kitchen Garden Cooking School", "zh": "泰式花园厨房烹饪学校"}, "description_i18n": {"th": "เริ่มเช้าด้วยการเดินตลาดต้นพยอมเลือกซื้อตะไคร้ ข่า ใบมะกรูดสด แล้วกลับมาตำน้ำพริกแกงเองกับครกหินก่อนลงมือผัดข้าวซอยไก่ แกงฮังเล และผัดไทยในกระทะเหล็กบนเตาแก๊สส่วนตัวของคุณ ปิดท้ายด้วยการห่อขนมตะโก้ใบเตยกลับบ้าน ทุกเมนูมีสูตรแจกให้ทำตามที่ห้องครัวกลางสวนร่มรื่นหลังย่านนิมมาน", "en": "Start the morning with a guided walk through Ton Phayom market to pick fresh lemongrass, galangal and kaffir lime, then return to pound your own curry paste in a stone mortar before stir-frying khao soi gai, hang lay curry and pad thai over your own gas wok station. You finish by wrapping pandan takoh dessert to take home. Every dish comes with a printed recipe, taught in an open garden kitchen just behind Nimman."}, "category": "do", "subcategory": "cooking_class", "lng": 98.9612, "lat": 18.7942, "opening_hours": {"mon": "09:00-14:00", "tue": "09:00-14:00", "wed": "09:00-14:00", "thu": "09:00-14:00", "fri": "09:00-14:00", "sat": "09:00-14:00, 16:00-20:00", "sun": "09:00-14:00"}, "amenities": ["booking_required", "english_speaking", "pickup_service", "beginner_friendly"], "price_band": "2", "phone": "+66 53 215 678"}$v$::jsonb, cid, did, agent, admin);
  PERFORM fn_create_place($v${"name_i18n": {"th": "เรือนไม้สปา นวดสมุนไพรล้านนา", "en": "Ruen Mai Lanna Herbal Spa", "zh": "兰纳木屋草本水疗"}, "description_i18n": {"th": "นอนลงบนเตียงไม้สักในเรือนกระจกท่ามกลางสวนเฟิร์น แล้วเลือกทรีตเมนต์นวดน้ำมันมะพร้าวสกัดเย็นผสมตะไคร้หอม ต่อด้วยการประคบลูกประคบสมุนไพรอุ่นที่นึ่งสดด้วยไพล ขมิ้น และการบูร เพื่อคลายกล้ามเนื้อหลังเดินเที่ยวทั้งวัน จบด้วยชาเก๊กฮวยร้อนและการแช่เท้าในน้ำดอกไม้ บรรยากาศเงียบสงบห่างจากถนนนิมมานเพียงไม่กี่อึดใจ", "en": "Lie down on a teak bed inside a glasshouse surrounded by a fern garden, then choose a cold-pressed coconut-oil massage infused with lemongrass, followed by a warm herbal compress freshly steamed with plai, turmeric and camphor to release muscles after a long day of walking. You end with a hot chrysanthemum tea and a flower-petal foot soak. A quiet retreat just minutes off Nimman road."}, "category": "do", "subcategory": "spa", "lng": 98.9785, "lat": 18.8031, "opening_hours": {"mon": "10:00-22:00", "tue": "10:00-22:00", "wed": "10:00-22:00", "thu": "10:00-22:00", "fri": "10:00-23:00", "sat": "10:00-23:00", "sun": "10:00-22:00"}, "amenities": ["booking_required", "english_speaking", "beginner_friendly"], "price_band": "3", "phone": "+66 81 472 9103"}$v$::jsonb, cid, did, agent, admin);
  PERFORM fn_create_place($v${"name_i18n": {"th": "ค่ายมวยไทยช้างเผือก เทรนนิ่ง", "en": "Chang Phueak Muay Thai Camp", "zh": "白象泰拳训练营"}, "description_i18n": {"th": "เริ่มคลาสด้วยการกระโดดเชือกและวอร์มอัพ ก่อนพันมือแล้วเข้าจับคู่ถือเป้ากับครูมวยอดีตนักชกสนามกีฬาเชียงใหม่ ฝึกหมัด ศอก เข่า เตะตามแบบฉบับมวยไทยแท้ในสังเวียนกลางแจ้งใต้ร่มไม้ใหญ่ มีกระสอบทรายหนักให้ซัดเต็มแรงและช่วงสปาร์ริงเบาๆ สำหรับคนพร้อม ปิดท้ายด้วยการยืดเหยียดและน้ำมะพร้าวเย็น เปิดรับตั้งแต่มือใหม่ไปจนถึงคนที่อยากฟิตจริงจัง", "en": "Class opens with skipping rope and a full warm-up before you wrap your hands and pair up on the pads with a kru who once fought at Chiang Mai Stadium, drilling authentic punches, elbows, knees and kicks in an open-air ring under a big shade tree. Heavy bags are there to hit at full power, with light sparring for those ready. You wind down with stretching and chilled coconut water. Open to total beginners through to serious fitness seekers."}, "category": "do", "subcategory": "muay_thai", "lng": 98.9683, "lat": 18.8094, "opening_hours": {"mon": "07:00-10:00, 16:00-19:00", "tue": "07:00-10:00, 16:00-19:00", "wed": "07:00-10:00, 16:00-19:00", "thu": "07:00-10:00, 16:00-19:00", "fri": "07:00-10:00, 16:00-19:00", "sat": "08:00-11:00", "sun": "Closed"}, "amenities": ["english_speaking", "beginner_friendly", "pickup_service"], "price_band": "2", "phone": "+66 89 556 2247"}$v$::jsonb, cid, did, agent, admin);
END $seed$;
SELECT 'VENUES total published='||count(*) AS seeded FROM places WHERE status='published';
